INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_41d9659b8276031c18',NULL,'swamp','/swɒmp/','n. 沼泽, 进退两难的困境\nvt. 淹没, 击溃, 清除, 使陷于沼泽\nvi. 陷于沼泽, 淹没；英英释义：n. low land that is seasonally flooded; has more woody plants than a marsh and better drainage than a bog\nn. a situation fraught with difficulties and imponderables\nv. drench or submerge or be drenched or submerged；词形变化：d:swamped/s:swamps/p:swamped/i:swamping/3:swamps','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c95557b67af7bfb8af',NULL,'swan','/swɒn/','n. 天鹅, 天鹅星座, 有才华的诗人\nvi. 闲荡, 蜿蜒而行；英英释义：n. stately heavy-bodied aquatic bird with very long neck and usually white plumage as adult\nv. sweep majestically；词形变化：s:swans/i:swanning/p:swanned/3:swans/d:swanned','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d18e56d676b41cc53e',NULL,'swarm','/swɒ:m/','n. 群, 大群, 蜂群, 分蜂群\nvi. 分群, 群集, 聚集一块, 云集, 攀\nvt. 挤满, 爬, 攀；英英释义：n. a group of many things in the air or on the ground；词形变化：p:swarmed/i:swarming/s:swarms/d:swarmed/3:swarms','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c85bebee1084d97a5d',NULL,'sway','/swei/','n. 摇摆, 影响力, 支配\nvt. 摇动, 支配, 弄歪, 使倾斜, 使动摇, 影响\nvi. 摇动, 摇摆, 倾斜, 动摇, 统治, 转向；英英释义：n. controlling influence；词形变化：i:swaying/p:swayed/d:swayed/s:sways/3:sways','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_feaa80af8cffddeb58',NULL,'swear','/swєә/','vt. 发誓, 咒骂, 使宣誓\nvi. 发誓, 诅咒\nn. 诅咒, 誓言；英英释义：v. promise solemnly; take an oath\nv. make a deposition; declare under oath；词形变化：d:sworn/p:swore/i:swearing/3:swears','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_fae818413b3d9e5835',NULL,'sweat','/swet/','n. 汗, 汗水, 水珠, 焦急\nvi. 出汗, 渗出, 冒出水气, 结水珠, 烦恼, 懊恼\nvt. 使出汗, 流出, 榨出, 使汗流浃背；英英释义：n. condensation of moisture on a cold surface\nv. excrete perspiration through the pores in the skin；词形变化：i:sweating/p:sweated/s:sweats/d:sweated/3:sweats','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_4e7e5a1e1e15939462',NULL,'sweater','/''swetә/','n. 毛衣, 毛线衫, 运动衫, 出汗者\n[化] 发汗器；英英释义：n. a crocheted or knitted garment covering the upper part of the body；词形变化：s:sweaters','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_eb0a7fdf6f223a21d5',NULL,'sweep','/swi:p/','n. 扫除, 打扫, 肃清, 视野, 范围, 全胜\nvt. 扫除, 掸去, 猛拉, 扫荡, 肃清, 冲走, 刮起, 环视, 掠过, 扫射\nvi. 扫, 打扫, 袭击, 席卷, 扫视, 掠过；英英释义：n. a wide scope\nn. a long oar used in an open boat\nn. a movement in an arc\nv. move with sweeping, effortless, gliding motions；词形变化：d:swept/p:swept/i:sweeping/3:sweeps/s:sweeps','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_530ca73d6712374627',NULL,'swell','/swel/','n. 增大, 隆起的部分, 巨浪, 肿胀\na. 优秀的, 一流的\nvi. 增大, 膨胀, 肿胀, 增强, 骄傲\nvt. 使膨胀, 使增大, 使上涨, 使骄傲；英英释义：n. the undulating movement of the surface of the open sea\nn. a rounded elevation (especially one on an ocean floor)\nn. a crescendo followed by a decrescendo\nv. increase in size, magnitude, number, or intensity；词形变化：d:swollen/i:swelling/p:swelled/s:swells/3:swells','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f0c69d0a17f7e3c46f',NULL,'swift','/swift/','n. 褐雨燕, 快速爬行的小蜥蜴, 蝙蝠蛾, 大滚筒\na. 迅速的, 快的, 敏捷的, 立刻的\nadv. 迅速地, 敏捷地；英英释义：n. United States meat-packer who began the use of refrigerated railroad cars (1839-1903)\nn. an English satirist born in Ireland (1667-1745)\nn. a small bird that resembles a swallow and is noted for its rapid flight；词形变化：s:swifts/r:swifter/t:swiftest','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_43bd404670199f1f98',NULL,'swing','/swiŋ/','n. 摇摆, 振幅, 音律, 节奏, 涨落, 秋千, 旋转, 行动自由\nvi. 摇摆, 悬挂, 旋转, 大摇大摆地走, 转向\nvt. 挥舞, 使旋转, 使转向, 悬挂, 吊运\na. 旋转的, 悬挂的, 强节奏爵士音乐的；英英释义：n. a state of steady vigorous action that is characteristic of an activity\nn. mechanical device used as a plaything to support someone swinging back and forth\nn. a sweeping blow or stroke\nn. changing location by moving back and forth；词形变化：p:swung/i:swinging/s:swings/d:swung/3:swings','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_6de5cecfce49c3b813',NULL,'switch','/switʃ/','n. 开关, 电闸, 转换, 软枝, 鞭子, 道岔\nvt. 转变, 切换, 摆动, 转换, 使转轨\nvi. 转换, 变换, 摆动\n[计] 开关; 翻转; 转移；英英释义：n. control consisting of a mechanical or electrical or electronic device for making or breaking or changing the connections in a circuit\nn. hairpiece consisting of a tress of false hair; used by women to give shape to a coiffure\nn. railroad track having two movable rails and necessary connections; used to turn a train from one track to another or to store rolling stock\nn. a flexible implement used as an instrument of punishment；词形变化：p:switched/d:switched/i:switching/s:switches/3:switches','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_187c40098bb49b5474',NULL,'sword','/sɒ:d/','n. 刀, 剑, 战争, 武力, 剑状物；英英释义：n. a cutting or thrusting weapon that has a long metal blade and a hilt with a hand guard；词形变化：s:swords','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_1a63e7d89ecbe57780',NULL,'symbol','/''simbl/','n. 符号, 象征, 代号, 信条\n[计] 符号; 码元；英英释义：n. an arbitrary sign (written or printed) that has acquired a conventional significance\nn. something visible that by association or convention represents something else that is invisible；词形变化：s:symbols','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_076be7fc636f92f997',NULL,'symmetry','/''simitri/','n. 对称, 匀称\n[化] 对称; 对称性; 对称现象；英英释义：n. (mathematics) an attribute of a shape or relation; exact reflection of form on opposite sides of a dividing line or plane\nn. balance among the parts of something；词形变化：s:symmetries','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e30eba424953899a55',NULL,'sympathetic','/.simpә''θetik/','a. 有同情心的, 合意的, 赞成的\nn. 交感神经, 容易感受的人；英英释义：a. of or relating to the sympathetic nervous system\na. expressing or feeling or resulting from sympathy or compassion or friendly fellow feelings; disposed toward\na. (of characters in literature or drama) evoking empathic or sympathetic feelings\ns. having similar disposition and tastes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_216b78e6b884411664',NULL,'sympathize','/''simpәθaiz/','vi. 同情, 怜悯, 同意, 体谅；英英释义：v. share the feelings of; understand the sentiments of\nv. be understanding of；词形变化：p:sympathized/3:sympathizes/d:sympathized/i:sympathizing','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_56a37ab198ff3b40c5',NULL,'sympathy','/''simpәθi/','n. 同情, 赞同, 怜悯, 慰问, 吊唁\n[医] 交感[作用], 同感[作用], 感应, 同情；英英释义：n. an inclination to support or be loyal to or to agree with an opinion\nn. sharing the feelings of others (especially feelings of sorrow or anguish)\nn. a relation of affinity or harmony between people; whatever affects one correspondingly affects the other；词形变化：s:sympathies','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_9967cb1826e045b32e',NULL,'symphony','/''simfәni/','n. 交响乐, 交响曲；英英释义：n. a long and complex sonata for symphony orchestra；词形变化：s:symphonies','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b127dbfabc732af413',NULL,'symposium','/sim''pәuziәm/','n. 讨论会, 座谈会, 专题报告会, 专题论文集；英英释义：n. a meeting or conference for the public discussion of some topic especially one in which the participants form an audience and make presentations；词形变化：s:symposiums','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d868a106734541265d',NULL,'symptom','/''simptәm/','n. 症状, 征候, 征兆\n[医] 症状；英英释义：n. (medicine) any sensation or change in bodily function that is experienced by a patient and is associated with a particular disease\nn. anything that accompanies X and is regarded as an indication of X''s existence；词形变化：s:symptoms','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d87d4348f425ba1a01',NULL,'synchronize','/''siŋkrәnaiz/','vt. 使同步, 使合拍\nvi. 同时发生\n[计] 同步；英英释义：v. make synchronous and adjust in time or manner\nv. happen at the same time\nv. make (motion picture sound) exactly simultaneous with the action\nv. arrange or represent events so that they co-occur；词形变化：d:synchronized/i:synchronizing/p:synchronized/3:synchronizes','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_2e0cd9f51bd480a384',NULL,'syndrome','/''sindrәum/','n. 并发症状, 综合征, 同时存在的事物\n[计] 校验子; 并发位；英英释义：n. a complex of concurrent things\nn. a pattern of symptoms indicative of some disease；词形变化：s:syndromes','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('3411cc2c-e716-4fa5-99c9-6141f3ddcc9c',NULL,'synthesis','/''sinθisis/','n. 综合, 组织, 综合体\n[化] 合成；英英释义：n. the process of producing a chemical compound (usually by the union of simpler chemical compounds)\nn. the combination of ideas into a complex whole；词形变化：s:syntheses','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_50bd7529ac67f1fe8f',NULL,'synthetic','/sin''θetik/','n. 合成物质\na. 综合(性)的, 人造的, 合成的；英英释义：n. a compound made artificially by chemical reactions\na. involving or of the nature of synthesis (combining separate elements to form a coherent whole) as opposed to analysis\na. systematic combining of root and modifying elements into single words\na. of a proposition whose truth value is determined by observation or facts；词形变化：s:synthetics','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_4bab8d702d4e4b5349',NULL,'system','/''sistәm/','n. 系统, 体系, 制度, 方式, 秩序, 分类原则\n[计] 系统; 体制; 体系；英英释义：n. instrumentality that combines interrelated interacting artifacts designed to work as a coherent entity\nn. a group of independent but interrelated elements comprising a unified whole\nn. (physical chemistry) a sample of matter in which substances in different phases are in equilibrium\nn. a complex of methods or rules governing behavior；词形变化：s:systems','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_95b11f8de3977f0725',NULL,'systematic','/.sisti''mætik/','a. 有系统的, 分类上的, 体系的\n[医] 系统的, 系的, 分类的；英英释义：a. characterized by order and planning；词形变化：s:systematics','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_dea7f2302d9a4b8e50',NULL,'tablet','/''tæblit/','n. 平板, 门牌, 笔记簿, 碑, 匾, 药片\n[化] 片剂；英英释义：n. a slab of stone or wood suitable for bearing an inscription\nn. a small flat compressed cake of some substance；词形变化：s:tablets','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_5af0d7b678ddc27821',NULL,'taboo','/tә''bu:/','n. 禁忌, 禁止接近, 禁止使用\na. 禁忌的, 忌讳的\nvt. 禁忌, 忌讳, 禁止；英英释义：n. a prejudice (especially in Polynesia and other South Pacific islands) that prohibits the use or mention of something because of its sacred nature\nn. an inhibition or ban resulting from social custom or emotional aversion\nv. declare as sacred and forbidden\ns. forbidden to profane use especially in South Pacific islands；词形变化：s:taboos','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f59e5ec021a9242921',NULL,'tackle','/''tækl/','n. 工具, 复滑车, 滑车, 装备, 扭倒\nvt. 固定, 处理, 抓住\nvi. 扭倒；英英释义：n. the person who plays that position on a football team\nn. (American football) a position on the line of scrimmage\nn. (American football) grasping an opposing player with the intention of stopping by throwing to the ground\nv. seize and throw down an opponent player, who usually carries the ball；词形变化：i:tackling/d:tackled/p:tackled/3:tackles/s:tackles','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e00e003e8d10d3d60c',NULL,'tactic','/''tæktik/','n. 一项战术, 一条策略\na. 战术的, 顺序的, 排列的；英英释义：n. a plan for attaining a particular goal；词形变化：s:tactics','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b78b304aa03ccf6f5f',NULL,'tag','/tæg/','n. 标签, 附属物, 碎片, 结束语, 口头禅, 附加语, 浑名, 标记, 标记符\nvt. 附以签条, 尾随, 添饰, 起浑名, 连接\nvi. 紧紧跟随\n[计] 标记；英英释义：n. a label written or printed on paper, cardboard, or plastic that is attached to something to indicate its owner, nature, price, etc.\nn. a label associated with something for the purpose of identification\nn. a game in which one child chases the others; the one who is caught becomes the next chaser\nn. (sports) the act of touching a player in a game (which changes their status in the game)；词形变化：s:tags/d:tagged/i:tagging/p:tagged/3:tags','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_fe58a976b511df5472',NULL,'tail','/teil/','n. 尾部, 后部, 辫子, 随员, 特务, 燕尾服, 踪迹, 限定继承(权)\na. 在后面的, 从后面而来的, 限定继承的, 尾部的, 后部的\nvt. 为...装尾, 附于其后, 尾随, 使搭牢, 跟踪, 监视\nvi. 跟踪, 船尾搁浅；英英释义：n. the posterior part of the body of a vertebrate especially when elongated and extending beyond the trunk or main part of the body\nn. any projection that resembles the tail of an animal\nn. a spy employed to follow someone and report their movements\nn. (usually plural) the reverse side of a coin that does not bear the representation of a person''s head；词形变化：s:tails/p:tailed/i:tailing/d:tailed/3:tails','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_82b98c0a36c74c86ab',NULL,'tailor','/''teilә/','n. 裁缝, 成衣匠\nvt. 缝制, 制作, 使适应\nvi. 做裁缝；英英释义：n. a person whose occupation is making and altering garments\nv. adjust to a specific need or market；词形变化：d:tailored/p:tailored/s:tailors/3:tailors/i:tailoring','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_289a718887184c077f',NULL,'tale','/teil/','n. 故事, 谎言, 谣言, 陈述, 叙述\n[法] 虚语, 诽语, 谣言；英英释义：n a message that tells the particulars of an act or occurrence or course of events; presented in writing or drama or cinema or as a radio or television program\nn a trivial lie；词形变化：s:tales','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_fcdefaf3f66881e165',NULL,'talent','/''tælәnt/','n. 天才, 才能, 有才干的人, 天资；英英释义：n. a person who possesses unusual innate ability in some field or activity；词形变化：s:talents','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_2186b6c8e6a8ae48c2',NULL,'tame','/teim/','a. 驯服的, 柔顺的, 被开垦的, 顺从的, 乏味的, 平淡的\nvt. 驯养, 驯服, 制服, 失去锋芒\nvi. 变得驯服；英英释义：v. correct by punishment or discipline\ns. flat and uninspiring\na. very restrained or quiet\na. brought from wildness into a domesticated state；词形变化：d:tamed/i:taming/p:tamed/r:tamer/3:tames','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_31b96d1568e1a91f3b',NULL,'tan','/tæn/','n. 黄褐色, 鞣料, 马戏团\na. 黄褐色的, 鞣皮的\nvi. 晒成棕褐色\nvt. 把...晒黑, 鞣(革), 狠狠鞭打；英英释义：n. a browning of the skin resulting from exposure to the rays of the sun\nn. a light brown the color of topaz\nv. treat skins and hides with tannic acid so as to convert them into leather\nv. get a tan, from wind or sun；词形变化：s:tans/p:tanned/d:tanned/i:tanning/3:tans','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('525c0805-bca9-4305-a864-440048bcec8b',NULL,'tangible','/''tændʒәbl/','n. 可触知的东西, 有形资产\na. 可触摸的, 有实体的, 非相像的, 有形的, 明确的；英英释义：a. perceptible by the senses especially the sense of touch\na. (of especially business assets) having physical substance and intrinsic monetary value；词形变化：s:tangibles','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8976806501ed603d12',NULL,'tangle','/''tæŋgl/','n. 缠结, 纠结的一团, 困惑, 纠纷, 混乱\nvt. 使缠结, 缠住\nvi. 缠结, 乱作一团；英英释义：n. a twisted and tangled mass that is highly interwoven\nn. something jumbled or confused；词形变化：s:tangles/p:tangled/d:tangled/i:tangling/3:tangles','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_32085779853b1d040d',NULL,'tank','/tæŋk/','n. 槽, 箱, 柜, 罐, 池塘, 储水池, 坦克\nvt. 储于箱中；英英释义：n. an enclosed armored military vehicle; has a cannon and moves on caterpillar treads\nn. a large (usually metallic) vessel for holding gases or liquids\nn. as much as a tank will hold\nv. store in a tank by causing (something) to flow into it；词形变化：s:tanks/i:tanking/p:tanked/3:tanks/d:tanked','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_9d48c319e0a37939f9',NULL,'tanker','/''tæŋkә/','n. 坦克手, 油船, 空中加油飞机, 运油飞机, 油槽/水槽汽车\n[化] 槽车; 油槽船；英英释义：n. a soldier who drives a tank；词形变化：s:tankers/d:tankered','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_35ec34af4b73f1fda0',NULL,'tap','/''tæp/','n. 轻打, 水龙头\nvt. 轻打, 轻敲, 敲打出, 选择, 装上嘴子, 使流出, 开发, 分接, 向...乞讨\nvi. 轻叩, 轻拍, 啪塔啪塔地走\n[计] 接头；英英释义：n. a small metal plate that attaches to the toe or heel of a shoe (as in tap dancing)\nn. a tool for cutting female (internal) screw threads\nn. a plug for a bunghole in a cask\nn. a light touch or stroke；词形变化：p:tapped/i:tapping/s:taps/d:tapped/3:taps','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_dad77ab8987a3ab404',NULL,'tape','/teip/','n. 带子, 录音带, 磁带, 窄带, 卷尺\nvt. 以带子绑起, 测量, 录音\n[计] 带；英英释义：n. a long thin piece of cloth or paper as used for binding or fastening\nn. a recording made on magnetic tape\nn. the finishing line for a foot race\nn. measuring instrument consisting of a narrow strip (cloth or metal) marked in inches or centimeters and used for measuring lengths；词形变化：s:tapes/i:taping/d:taped/p:taped/3:tapes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ded4072785dd148bc1',NULL,'tar','/tɑ:/','n. 焦油, 柏油, 水手\nvt. 涂以焦油, 玷污, 怂恿\na. 焦油的；英英释义：v. coat with tar；词形变化：d:tarred/p:tarred/s:tars/i:tarring/3:tars','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b02b023ac819cb5a0a',NULL,'target','/''tɑ:git/','n. 目标, 靶子, 指标\nvt. 对准, 订指标；英英释义：n. a reference point to shoot at\nn. the location of the target that is to be hit\nn. sports equipment consisting of an object set up for a marksman or archer to aim at\nv. intend (something) to move towards a certain goal；词形变化：s:targets/d:targeted/i:targeting/p:targeted/3:targets','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_5ce968ef944822c769',NULL,'tariff','/''tærif/','n. 关税, 关税表, 价格表, 收费表\nvt. 课以关税\n[计] 价目表；英英释义：v. charge a tariff；词形变化：s:tariffs/i:tariffing/p:tariffed/3:tariffs/d:tariffed','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_de0e46e429dc5dee42',NULL,'task','/tɑ:sk/','n. 工作, 任务, 作业, 困难的工作\nvt. 派给...工作, 使辛劳\n[计] 任务；英英释义：v. assign a task to；词形变化：s:tasks/d:tasked/i:tasking/p:tasked/3:tasks','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_381d3716e3e21ce947',NULL,'taste','/teist/','n. 味道, 品味, 味觉, 感受, 体验, 爱好, 审美, 少量\nvt. 尝, 察觉...的味道, 体会\nvi. 品尝, 察觉味道, 有某种味道；英英释义：n. the sensation that results when taste buds in the tongue and throat convey information about the chemical composition of a soluble stimulus\nn. delicate discrimination (especially of aesthetic values)\nn. a brief experience of something\nn. a small amount eaten or drunk；词形变化：s:tastes/p:tasted/d:tasted/3:tastes/i:tasting','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b28b714a2995e20def',NULL,'tax','/tæks/','n. 税, 税款, 重负, 会费\nvt. 课以税, 使负重荷, 斥责；英英释义：n. charge against a citizen''s person or property or activity for the support of government\nv. levy a tax on\nv. set or determine the amount of (a payment such as a fine)\nv. use to the limit；词形变化：s:taxes/d:taxed/p:taxed/i:taxing/3:taxes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_04c487f7961761e981',NULL,'team','/ti:m/','n. 队, 组\nvt. 把马(牛)套在同一辆车上, 把...编成一组\nvi. 驾驶卡车, 协作；英英释义：n. a cooperative unit (especially in sports)\nn. two or more draft animals that work together to pull something\nv. form a team；词形变化：s:teams/d:teamed/p:teamed/i:teaming/3:teams','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8d06ffcafa717492da',NULL,'tear','/tiә. tєә/','n. 泪滴, 眼泪, 撕, 扯, 裂缝, 激怒, 飞奔\nvi. 流泪, 撕破, 赶快, 飞奔, 被撕破\nvt. 撕裂, 戳破, 拉掉, 撕掉, 使分裂, 使精神不安, 折磨；英英释义：n. a drop of the clear salty saline solution secreted by the lacrimal glands\nn. the act of tearing\nv. separate or cause to separate abruptly\nv. to separate or be separated by force；词形变化：s:tears/d:torn/p:tore/i:tearing/3:tears','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8eeaf78091d53222fc',NULL,'tease','/ti:z/','n. 揶揄, 戏弄, 逗惹\nvt. 戏弄, 取笑, 强求, 梳理, 使起毛；英英释义：n. someone given to teasing (as by mocking or stirring curiosity)\nn. the act of harassing someone playfully or maliciously (especially by ridicule); provoking someone with persistent annoyances\nv. annoy persistently\nv. harass with persistent criticism or carping；词形变化：p:teased/i:teasing/d:teased/3:teases/s:teases','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_3f354fe37dd406d29d',NULL,'technical','/''teknikl/','a. 技术上的, 专门的, 工业的, 严格根据法律的\n[化] 技巧；英英释义：n. a pickup truck with a gun mounted on it\na. of or relating to technique or proficiency in a practical skill\na. characterizing or showing skill in or specialized knowledge of applied arts and sciences\na. of or relating to a practical subject that is organized according to scientific principles','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
