INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_bc74f9e5091188b19e',NULL,'tend','/tend/','vi. 走向, 有某种的倾向, 易于, 照顾, 注意\nvt. 照料, 护理；英英释义：v. have a tendency or disposition to do or be something; be inclined\nv. have care of or look after\nv. manage or run；词形变化：3:tends/p:tended/d:tended/i:tending','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
