INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_afe5ea50848612e469',NULL,'tender','/''tendә/','a. 嫩的, 柔软的, 脆弱的, 温柔的, 亲切的, 未成熟的, 微妙的, 棘手的, 审慎的\nvt. 使变嫩, 提供, 偿还\nvi. 变柔软, 投标\nn. 照料, 看管人, 供应船, 小船, 提出, 偿付, 投标；英英释义：n. something that can be used as an official medium of payment\nn. car attached to a locomotive to carry fuel and water\nn. a boat for communication between ship and shore\nn. ship that usually provides supplies to other ships；词形变化：s:tenders/d:tendered/p:tendered/i:tendering/3:tenders','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
