INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_a063d8d8368aaaaa2b',NULL,'tension','/''tenʃәn/','n. 紧张, 不安, 拉紧, 张力, 压力, 电压\nvt. 拉紧, 使紧张；英英释义：n. (psychology) a state of mental or emotional strain or suspense\nn. the physical condition of being stretched or strained\nn. a balance between and interplay of opposing elements or tendencies (especially in art or literature)\nn. (physics) a stress that produces an elongation of an elastic physical body；词形变化：s:tensions/d:tensioned','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_fe365eed14be7af89f',NULL,'tent','/tent/','n. 帐篷, 帷幕, 住处, 塞条, 塞子\nvi. 住帐蓬, 宿营, 暂时居住\nvt. 用帐篷遮盖, 使住帐篷, 用塞条嵌入；英英释义：n. a portable shelter (usually of canvas stretched over supporting poles and fastened to the ground with ropes and pegs)\nn. a web that resembles a tent or carpet；词形变化：s:tents/p:tented/i:tenting/3:tents/d:tented','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
