INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_adcd12b52b0441fa0d',NULL,'thrill','/θril/','n. 震颤, 激动, 刺激性, 一阵激动\nvi. 震颤, 颤抖, 激动\nvt. 使激动, 使颤动；英英释义：n. something that causes you to experience a sudden intense feeling or sensation\nv. cause to be thrilled by some perceptual input\nv. feel sudden intense sensation or emotion；词形变化：s:thrills/3:thrills/i:thrilling/p:thrilled/d:thrilled','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_066065f29870d94efa',NULL,'thrive','/θraiv/','vi. 繁荣, 兴旺, 茁壮成长\n[经] 兴旺, 繁荣, 旺盛；英英释义：v. make steady progress; be at the high point in one''s career or reach a high point in historical significance or importance；词形变化：3:thrives/p:thrived/i:thriving/d:thrived','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_5346b5c520c1933e0e',NULL,'throat','/θrәut/','n. 咽喉, 喉咙, 嗓音\nvt. 用喉音说, 开沟于；英英释义：n. the passage to the stomach and lungs; in the front part of the neck below the chin and above the collarbone\nn. an opening in the vamp of a shoe at the instep\nn. a passage resembling a throat in shape or function; \nn. the part of an animal''s body that corresponds to a person''s throat；词形变化：s:throats','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_526f31a6313ba268be',NULL,'throne','/''θrәun/','n. 王座, 君主；英英释义：n. the chair of state for a monarch, bishop, etc.\nn. the position and power of an exalted person (a sovereign or bishop) who is entitled to sit in a chair of state on ceremonial occasions\nv. sit on the throne as a ruler；词形变化：s:thrones/i:throning/p:throned/3:thrones/d:throned','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_5a217e99ac02ff0685',NULL,'throughout','/θru:''aut/','adv. 到处, 贯穿全部地, 自始至终\nprep. 遍及, 在各处\n[计] 吞吐量；英英释义：r. from first to last','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d80be2fbca083b6d1b',NULL,'thrust','/θrʌst/','n. 插, 戳, 刺, 猛推, 口头攻击, 推力\nvt. 插入, 猛推, 刺, 戳, 强加, 延伸\nvi. 插, 刺, 戳, 延伸, (用力)推；英英释义：n. verbal criticism\nv. push forcefully\nv. press or force\nv. force (molten rock) into pre-existing rock；词形变化：p:thrust/0:thrust/1:pd/d:thrust/i:thrusting/s:thrusts/3:thrusts','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_a3cff02f1bd8209e5a',NULL,'thumb','/θʌm/','n. 拇指\nvt. 以拇指拨弄, 笨拙地摆弄, 用拇指翻旧, 迅速翻阅, 作搭车手势；英英释义：n. the thick short innermost digit of the forelimb\nn. the part of a glove that provides a covering for the thumb；词形变化：s:thumbs/p:thumbed/i:thumbing/3:thumbs/d:thumbed','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d87788b5bed9d5c2af',NULL,'thunder','/''θʌndә/','n. 雷, 雷声\nvi. 打雷, 轰隆地响, 怒喝\nvt. 大声喊出, 轰隆地发出；英英释义：n. a booming or crashing noise caused by air expanding along the path of a bolt of lightning\nv. move fast, noisily, and heavily\nv. utter words loudly and forcefully\nv. be the case that thunder is being heard；词形变化：p:thundered/i:thundering/s:thunders/d:thundered/3:thunders','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_69c31c91278588a4d9',NULL,'thus','/ðʌs/','adv. 如此, 因此, 到如此程度\n[医] 乳香；英英释义：r. in the way indicated; (`thusly'' is a nonstandard variant)','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_385a3f13eeb0619108',NULL,'tick','/tik/','n. 滴答声, 一瞬间, 壁虱, 褥套, 信用, 赊欠\nvi. 滴答响, 活动\nvt. 滴答地记录, 标记号于；英英释义：n. a metallic tapping sound\nn. any of two families of small parasitic arachnids with barbed proboscis; feed on blood of warm-blooded animals\nn. a light mattress\nv. make a sound like a clock or a timer；词形变化：i:ticking/s:ticks/p:ticked/d:ticked/3:ticks','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ba3aa0dbefa9dbd1fe',NULL,'tide','/taid/','n. 潮, 潮汐, 趋势, 潮流, 涨潮, 高潮\nvt. 使随潮漂流\nvi. 顺潮行驶；英英释义：n. the periodic rise and fall of the sea level under the gravitational pull of the moon\nn. something that may increase or decrease (like the tides of the sea)\nn. there are usually two high and two low tides each day\nv. rise or move forward；词形变化：s:tides/i:tiding/p:tided/3:tides/d:tided','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_29c9d8a15f534b3808',NULL,'tidy','/''taidi/','n. 椅子的背罩, 装杂物的容器\na. 整齐的, 有条理的\nvt. 弄整齐, 收拾, 整理\nvi. 整理, 收拾；英英释义：n. receptacle that holds odds and ends (as sewing materials)\nv. put (things or places) in order\na. marked by order and cleanliness in appearance or habits；词形变化：i:tidying/p:tidied/d:tidied/r:tidier/3:tidies/t:tidiest/s:tidies','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8a5e87a6aff6c6156c',NULL,'tie','/tai/','n. 带子, 线, 鞋带, 领带, 领结, 关系, 束缚, 平局, 不分胜负\nvt. 系, 打结, 扎, 约束, 与...成平局\nvi. 结合, 打结, 不分胜负；英英释义：n. equality of score in a contest\nn. a horizontal beam used to prevent two other structural members from spreading apart or separating\nn. (music) a slur over two notes of the same pitch; indicates that the note is to be sustained for their combined time value\nn. one of the cross braces that support the rails on a railway track；词形变化：d:tied/s:ties/p:tied/i:tying/3:ties','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0308f8a91e711fea1d',NULL,'tiger','/''taigә/','n. 老虎, 虎, 凶暴的人；英英释义：n. a fierce or audacious person\nn. large feline of forests in most of Asia having a tawny coat with black stripes; endangered；词形变化：s:tigers','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_59b03828ae65de9dea',NULL,'tight','/tait/','a. 紧的, 密封的, 吝啬的, 严厉的\nadv. 紧紧地；英英释义：a. closely constrained or constricted or constricting\ns. set so close together as to be invulnerable to penetration\ns. affected by scarcity and expensive to borrow\na. of such close construction as to be impermeable；词形变化：r:tighter/s:tights/t:tightest','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_462d555918cf93a234',NULL,'tile','/tail/','n. 砖瓦, 瓷砖, 瓦片\nvt. 铺以瓦, 铺以瓷砖\n[计] 平铺；英英释义：n. a flat thin rectangular slab (as of fired clay or rubber or linoleum) used to cover surfaces\nn. a thin flat slab of fired clay used for roofing\nn. game equipment consisting of a flat thin piece marked with characters and used in board games like Mah-Jong, Scrabble, etc.\nv. cover with tiles；词形变化：s:tiles/d:tiled/i:tiling/p:tiled/3:tiles','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_5ee5b58b4d596c6132',NULL,'tilt','/tilt/','n. 倾斜, 倾向, 船篷, 车篷\nvt. 使倾斜, 使倾侧, 用帆布篷遮盖\nvi. 倾斜, 翘起, 冲, 评击\n[计] 倾斜；英英释义：n. a slight but noticeable partiality\nn. the property possessed by a line or surface that departs from the vertical\nv. charge with a tilt；词形变化：p:tilted/i:tilting/d:tilted/3:tilts/s:tilts','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
