INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c8839173ef4af0c784',NULL,'transcend','/træn''send/','vt. 超越, 胜过；英英释义：v be greater in scope or size than some standard\nv be superior or better than some standard；词形变化：3:transcends/p:transcended/i:transcending/d:transcended','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ac1cb98e700964a1aa',NULL,'transcendent','/træn''sendәnt/','a. 卓越的, 出类拔萃的, 超常的\nn. 卓越的人, 超绝物；英英释义：s. exceeding or surpassing usual limits especially in excellence\ns. beyond and outside the ordinary range of human experience or understanding','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
