INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_bb4a4c63b726c15179',NULL,'transform','/træns''fɒ:m/','vt. 使转换, 改变, 改造, 使...变形\nvi. 改变, 转化, 变换\n[计] 变换；英英释义：v. subject to a mathematical transformation\nv. change or alter in form, appearance, or nature\nv. change in outward structure or looks\nv. convert (one form of energy) to another；词形变化：d:transformed/i:transforming/p:transformed/3:transforms','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_7f3e687ec58906b819',NULL,'transient','/''trænziәnt/','n. 瞬, 短期居留者, 过境鸟, 瞬变现象\na. 短暂的, 易变的, 瞬变的, 路过的\n[计] 瞬变过程; 过渡过程; 过渡的; 瞬变的; 瞬时峰值电压；英英释义：n. one who stays for only a short time\nn. (physics) a short-lived oscillation in a system caused by a sudden change of voltage or current or load；词形变化：s:transients','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
