INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0f21508c944d4ee4d3',NULL,'transition','/træn''ziʃәn/','n. 转变, 转换, 变迁, 过渡时期, 临时转调\n[化] 跃迁；英英释义：n. a change from one place or state or subject or stage to another\nn. a musical passage moving from one key to another\nn. a passage that connects a topic to one that follows\nv. cause to convert or undergo a transition；词形变化：s:transitions/d:transitioned/i:transitioning/p:transitioned/3:transitions','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c4b10f2d0b9277737c',NULL,'translate','/træns''leit/','vt. 翻译, 解释, 转化, 转变为, 调动\nvi. 翻译, 被译\n[计] 转换；英英释义：v. restate (words) from one language into another language\nv. change from one form or medium into another\nv. bring to a certain spiritual state\nv. change the position of (figures or bodies) in space without rotation；词形变化：d:translated/i:translating/3:translates/p:translated','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e1681cc9deebae67f2',NULL,'translation','/træns''leiʃәn/','n. 翻译, 译文, 转化, 调任, 平移, 转译\n[计] 转换；英英释义：n. a written communication in a second language having the same meaning as the written communication in a first language\nn. a uniform movement without rotation\nn. (mathematics) a transformation in which the origin of the coordinate system is moved to another position but the direction of each axis remains the same\nn. (genetics) the process whereby genetic information coded in messenger RNA directs the formation of a specific protein at a ribosome in the cytoplasm；词形变化：s:translations','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_a2d30b381f2e5b60b5',NULL,'transmission','/træns''miʃәn/','n. 传输, 传送, 变速器\n[计] 传输；英英释义：n. the act of sending a message; causing a message to be transmitted\nn. communication by means of transmitted signals\nn. the gears that transmit power from an automobile engine via the driveshaft to the live axle；词形变化：s:transmissions','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e48f70aa79cdf65450',NULL,'transmit','/træns''mit/','vt. 传输, 传染, 传达, 遗传, 发射, 传播\nvi. 发射信号, 留传下来\n[计] 传送；英英释义：v. send from one person or place to another；词形变化：d:transmitted/i:transmitting/p:transmitted/3:transmits','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
