INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_24f71f2a8cf705dfcd',NULL,'trend','/trend/','n. 趋势, 倾向, 走向\nvi. 倾向, 转向\n[计] 趋势；英英释义：n a general direction in which something tends to move\nn general line of orientation\nn a general tendency to change (as of opinion)\nn the popular taste at a given time\nv turn sharply; change direction abruptly；词形变化：s:trends/i:trending/p:trended/3:trends/d:trended','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_1e8c8f4feeb1fe7ce2',NULL,'trial','/''traiәl/','n. 审判, 试验, 艰苦, 麻烦事, 考验\na. 审讯的, 试验性的；英英释义：n. trying something to find out about it\nn. (law) the determination of a person''s innocence or guilt by due process of law\nn. (sports) a preliminary competition to determine qualifications\nn. an annoying or frustrating or catastrophic event；词形变化：s:trials/p:trialled','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
