INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_765e234883b1552092',NULL,'trumpet','/''trʌmpit/','n. 喇叭, 小号, 喇叭声\nvi. 吹喇叭\nvt. 用喇叭吹出, 吹嘘；英英释义：v. proclaim on, or as if on, a trumpet\nv. play or blow on the trumpet\nv. utter in trumpet-like sounds；词形变化：s:trumpets/3:trumpets/i:trumpeting/p:trumpeted/d:trumpeted','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
