INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8edf60a004b29239c3',NULL,'vacation','/vei''keiʃәn/','n. 假期, 休假\n[法] 假期, 停审期, 休庭期；英英释义：n. leisure time away from work devoted to rest or pleasure\nn. the act of making something legally void\nv. spend or take a vacation；词形变化：s:vacations/i:vacationing/p:vacationed/3:vacations/d:vacationed','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8de3430a4fde24a99c',NULL,'vacuum','/''''vækjuәm/','n. 真空, 空间, 真空吸尘器\na. 真空的, 产生真空的, 利用真空的\nvt. 用吸尘器打扫；英英释义：n. the absence of matter\nn. a region that is devoid of matter\nn. an electrical home appliance that cleans by suction\nv. clean with a vacuum cleaner；词形变化：s:vacuums/3:vacuums/i:vacuuming/p:vacuumed/d:vacuumed','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
