INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_48497de33475dfc1a8',NULL,'valid','/''vælid/','a. 有确实根据的, 有法律效力的, 正当的, 正确的\n[经] 有效的；英英释义：a. well grounded in logic or truth or having legal force\ns. still legally acceptable','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_75d7e8fe1caedc5ca9',NULL,'valley','/''væli/','n. 山谷, 溪谷, 流域, 凹地\n[医] 谷；英英释义：n. a long depression in the surface of the land that usually contains a river；词形变化：s:valleys','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_bf7fab39b71ac6fe0f',NULL,'valuable','/''væljuәbl/','a. 有价值的, 贵重的, 宝贵的, 可估价的\n[经] 有价值的, 可估价的, 贵重的；英英释义：n. something of value\na. having great material or monetary value especially for use or exchange\ns. having worth or merit or value','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_a79c4b45a93e020006',NULL,'value','/''vælju:/','n. 价值, 价格, 购买力, 评价, 估价, 计算结果\nvt. 评价, 估价, 重视\n[计] 计算结果；英英释义：n. a numerical quantity measured or assigned or computed\nn. the quality (positive or negative) that renders something desirable or valuable\nn. the amount (of money or goods or services) that is considered to be a fair equivalent for something else\nn. relative darkness or lightness of a color；词形变化：s:values/d:valued/p:valued/i:valuing/3:values','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_85b86d7c63f9c02f1a',NULL,'valve','/vælv/','n. 活瓣, 阀, 活门\nv. 装阀, 用阀调节；英英释义：n. a structure in a hollow organ (like the heart) with a flap to insure one-way flow of fluid through it\nn. device in a brass wind instrument for varying the length of the air column to alter the pitch of a tone\nn. control consisting of a mechanical device for controlling the flow of a fluid\nn. the entire one-piece shell of a snail and certain other molluscs；词形变化：s:valves/d:valved','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_016083593e77f2f329',NULL,'van','/væn/','n. 货车, 篷车, 先锋, 前驱, 前卫\nvt. 用货车搬运\n[计] 增值网；英英释义：n. (Great Britain) a closed railroad car that carries baggage or freight\nn. a camper equipped with living quarters\nn. a truck with an enclosed cargo space；词形变化：s:vans','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_cca4ffba488be3f926',NULL,'vanish','/''væniʃ/','vi. 消失, 不见, 成为零；英英释义：v. become invisible or unnoticeable\nv. cease to exist\nv. decrease rapidly and disappear；词形变化：p:vanished/d:vanished/3:vanishes/i:vanishing','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_56df9ff5637f5dc443',NULL,'vanity','/''væniti/','n. 虚荣心, 虚无, 自负, 空虚, 时髦的小摆饰；英英释义：n. the quality of being valueless or futile；词形变化：s:vanities','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_9e82e011a6b4cd44c6',NULL,'vapour','/''veipә/','n. 汽, 蒸气\nvi. 蒸发, 吹牛\nvt. 使蒸发, 使汽化；英英释义：n a visible suspension in the air of particles of some substance\nn the process of becoming a vapor；词形变化：s:vapours/i:vapouring','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b8cc391b87a28d02b3',NULL,'variable','/''vєәriәbl/','n. 易变的事物, 变数, 可变物, 变量\na. 可变的, 不定的, 易变的, 变量的\n[计] 变量；英英释义：n. something that is likely to vary; something that is subject to variation\nn. a quantity that can assume any of a set of values\nn. a symbol (like x or y) that is used in mathematical or logical expressions to represent a variable quantity\na. liable to or capable of change；词形变化：s:variables','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e9d82fc590e9c51cae',NULL,'variation','/.vєәri''eiʃәn/','n. 变更, 变化, 变种, 变奏\n[医] 变异, 变易; 变度；英英释义：n. an instance of change; the rate or magnitude of change\nn. an activity that varies from a norm or standard\nn. a repetition of a musical theme in which it is modified or embellished\nn. an artifact that deviates from a norm or standard；词形变化：s:variations','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_398d0b4dc41391e41c',NULL,'variety','/vә''raiәti/','n. 多样, 种类, 变种, 杂耍\n[化] 变种；英英释义：n. (biology) a taxonomic category consisting of members of a species that differ from others of the same species in minor but heritable characteristics\nn. a difference that is usually pleasant；词形变化：s:varieties','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8bfb72ee3eef6e2e1f',NULL,'various','/''vєәriәs/','a. 不同的, 各种的, 多方面的, 许多的, 个别的, 杂色的\n[法] 不同的, 种种的, 各式各样的；英英释义：s of many different kinds purposefully arranged but lacking any uniformity\ns considered individually\ns distinctly dissimilar or unlike\ns having great diversity or variety','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
