INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d9b89e813328462145',NULL,'vase','/veis/','n. 花瓶, 瓶；英英释义：n. an open jar of glass or porcelain used as an ornament or to hold flowers；词形变化：s:vases','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
