INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_2d8b833db78d038778',NULL,'vegetarian','/.vedʒi''tєәriәn/','n. 素食者, 食草动物\na. 素食的；英英释义：n. eater of fruits and grains and nuts; someone who eats no meat or fish or (often) any animal products；词形变化：s:vegetarians','','考研核心·学术','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_3898608b0a96785613',NULL,'vegetation','/.vedʒi''teiʃәn/','n. 植物\n[医] 贽生物, 贽疣, 增殖体; 生长, 增殖；英英释义：n. all the plant life in a particular region or period\nn. the process of growth in plants\nn. an abnormal growth or excrescence (especially a warty excrescence on the valves of the heart)\nn. inactivity that is passive and monotonous, comparable to the inactivity of plant life','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
