INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_59b952f9931ccb8535',NULL,'veil','/veil/','n. 面纱, 面罩, 借口, 幕, 帐, 遮蔽物\nvt. 戴面纱, 隐藏, 遮蔽, 掩饰\nvi. 蒙上面纱；英英释义：n. a membranous covering attached to the immature fruiting body of certain mushrooms\nv. to obscure, or conceal with or as if with a veil；词形变化：s:veils/d:veiled/p:veiled/i:veiling/3:veils','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c25b83084e9d7936b1',NULL,'vein','/vein/','n. 血管, 静脉, 纹理, 气质, 情绪\nvt. 使有脉络, 像脉络般分布于；英英释义：n. a blood vessel that carries blood from the capillaries toward the heart\nn. a distinctive style or manner\nn. any of the vascular bundles or ribs that form the branching framework of conducting and supporting tissues in a leaf or other plant organ\nn. a layer of ore between layers of rock；词形变化：s:veins/d:veined/i:veining/p:veined/3:veins','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e79ece4ecd00ab4c58',NULL,'velocity','/vi''lɒsәti/','n. 速度, 迅速\n[化] 速度；英英释义：n distance travelled per unit time；词形变化：s:velocities','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
