INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_d0fc279f37b6f6ac1d',NULL,'ventilate','/''ventileit/','vt. 使空气流通, 使通风, 公开讨论, 公开\n[医] 通风, 换气；英英释义：v. expose to the circulation of fresh air so as to retard spoilage\nv. circulate through and freshen\nv. furnish with an opening to allow air to circulate or gas to escape；词形变化：d:ventilated/i:ventilating/3:ventilates/p:ventilated','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
