INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_129b732cce89476163',NULL,'voice','/vɒis/','n. 声音, 嗓音, 嗓子, 愿望, 发言权, 表达, 喉舌, 语态\nvt. 表达, 吐露, 调音；英英释义：n. the distinctive quality or pitch or condition of a person''s speech\nn. the sound made by the vibration of vocal folds modified by the resonance of the vocal tract\nn. a sound suggestive of a vocal utterance\nn. a means or agency by which something is expressed or communicated；词形变化：s:voices/d:voiced/p:voiced/i:voicing/3:voices','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
