INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e9a76417bcfff178fa',NULL,'ward','/wɒ:d/','n. 病房, 守卫, 保卫, 保护, 监护, 牢房, 行政区, 锁孔内的榫舌\nvt. 使入病房, 守护, 保卫；英英释义：n. a person who is under the protection or in the custody of another\nn. a district into which a city or town is divided for the purpose of administration and elections\nn. block forming a division of a hospital (or a suite of rooms) shared by patients who need a similar kind of care\nn. English economist and conservationist (1914-1981)；词形变化：s:wards/i:warding/d:warded/p:warded/3:wards','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
