INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_c250f58de031ec1bbd',NULL,'warehouse','/''wєәhaus/','n. 仓库, 货栈, 大商店\nvt. 储入仓库；英英释义：n. a storehouse for goods and merchandise\nv. store in a warehouse；词形变化：s:warehouses/p:warehoused/i:warehousing/3:warehouses/d:warehoused','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
