INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_1fba80b907b4aafb0a',NULL,'warn','/wɒ:n/','vt. 警告, 提醒, 通知\nvi. 发出警告；英英释义：v. notify of danger, potential harm, or risk\nv. admonish or counsel in terms of someone''s behavior\nv. ask to go away\nv. notify, usually in advance；词形变化：p:warned/d:warned/3:warns/i:warning','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('21bf102a-c4ef-426c-910c-b8c3de671102',NULL,'warrant','/''wɒ:rәnt/','n. 授权, 正当理由, 根据, 证明, 批准, 凭证, 令状, 委任状\nvt. 授权给, 保证, 担保, 批准, 使有正当理由；英英释义：n. a writ from a court commanding police to perform specified acts\nn. a type of security issued by a corporation (usually together with a bond or preferred stock) that gives the holder the right to purchase a certain amount of common stock at a stated price；词形变化：s:warrants/3:warrants/d:warranted/p:warranted/i:warranting','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_5a327f2c3bcd9bd3b9',NULL,'waste','/weist/','n. 浪费, 废物, 损耗, 消耗, 荒地, 垃圾, 地面风化物\na. 废弃的, 荒芜的, 多余的\nvt. 浪费, 消耗, 使荒芜\nvi. 浪费, 消耗, 变消瘦；英英释义：n. any materials unused and rejected as worthless or unwanted\nn. useless or profitless activity; using or expending or consuming thoughtlessly or carelessly\nn. (law) reduction in the value of an estate caused by act or neglect\nv. spend thoughtlessly; throw away；词形变化：i:wasting/d:wasted/s:wastes/p:wasted/3:wastes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_1776393297d8dcddc3',NULL,'waterfall','/''wɒtәfɒ:l/','n. 瀑布；英英释义：n. a steep descent of the water of a river；词形变化：s:waterfalls','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ec0fd476010f4ff29c',NULL,'waterproof','/''wɒtәpru:f/','n. 防水材料\na. 不透水的, 防水的\nvt. 使防水；英英释义：n. any fabric impervious to water\nv. make watertight；词形变化：s:waterproofs/d:waterproofed/i:waterproofing/p:waterproofed/3:waterproofs','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_47208a6668f324a369',NULL,'watt','/wɒt/','n. 瓦(特)\n[化] 瓦; 瓦特；英英释义：n. a unit of power equal to 1 joule per second; the power dissipated by a current of 1 ampere flowing across a resistance of 1 ohm\nn. Scottish engineer and inventor whose improvements in the steam engine led to its wide use in industry (1736-1819)；词形变化：s:watts','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_f80bd2020bf6798862',NULL,'wave','/weiv/','n. 波, 波浪, 波动, 起伏, 高潮, 潮涌, 挥手致意, (气压)突变\nvi. 波动, 飘动, 挥手示意, 起伏\nvt. 使波动, 使飘扬, 挥舞, 使成波浪形；英英释义：n. one of a series of ridges that moves across the surface of a liquid (especially across a large body of water)\nn. a movement like that of a sudden occurrence or increase in a specified phenomenon\nn. (physics) a movement up and down or back and forth\nn. something that rises rapidly；词形变化：s:waves/p:waved/i:waving/d:waved/3:waves','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_751c0b20324bc51ed8',NULL,'wax','/wæks/','n. 蜡, 蜡状物, 一阵发怒, 增加, (月亮)渐盈\nvi. 变大, 增大, 月亮渐满\nvt. 上蜡于；英英释义：n. any of various substances of either mineral origin or plant or animal origin; they are solid at normal temperatures and insoluble in water\nv. cover with wax\nv. go up or advance\nv. increase in phase；词形变化：i:waxing/p:waxed/s:waxes/3:waxes/d:waxed','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_7d6b83f00481f98f96',NULL,'weak','/wi:k/','a. 不牢固的, 弱的, 虚弱的, 软弱的, 无力的, 无权力的, (论据等)不充分的\n[经] 疲软的；英英释义：a. wanting in physical strength\ns. tending downward in price\ns. deficient or lacking in some skill\ns. (used of verbs) having standard (or regular) inflection；词形变化：r:weaker/t:weakest','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0b38717c76eb7b55a5',NULL,'wealth','/welθ/','n. 财富, 资源, 财产, 丰富, 富裕, 大量\n[经] 财富；英英释义：n. the state of being rich and affluent; having a plentiful supply of material goods and money\nn. the quality of profuse abundance\nn. an abundance of material possessions and resources\nn. property that has economic utility: a monetary value or an exchange value','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b6d900235b7cf0f8c1',NULL,'wealthy','/''welθi/','a. 富有的, 丰裕的, 充分的；英英释义：s having an abundant supply of money or possessions of value；词形变化：r:wealthier/t:wealthiest','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_b6417920d61ca7af60',NULL,'weapon','/''wepәn/','n. 武器, 兵器\nvt. 武装；英英释义：n. any instrument or instrumentality used in fighting or hunting\nn. a means of persuading or arguing；词形变化：s:weapons','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_e509aa75a5a65becf8',NULL,'weary','/''wiәri/','a. 疲倦的, 萎靡的, 厌倦的, 厌烦的\nvt. 使疲倦, 使厌烦\nvi. 疲乏, 生厌, 不耐烦；英英释义：v exhaust or get tired through overuse or great strain or stress\nv lose interest or become bored with something or somebody\ns physically and mentally fatigued；词形变化：d:wearied/i:wearying/p:wearied/r:wearier/s:wearies/t:weariest/3:wearies','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_8172ff65ab3ad39ce3',NULL,'weave','/wi:v/','n. 编法, 织法, 编织式样\nvt. 编织, 组合, 编排, 使迂回前进\nvi. 纺织, 迂回行进；英英释义：n. pattern of weaving or structure of a fabric\nv. interlace by or as if by weaving\nv. create a piece of cloth by interlacing strands of fabric, such as wool or cotton\nv. to move or cause to move in a sinuous, spiral, or circular course；词形变化：d:woven/i:weaving/p:wove/3:weaves/s:weaves','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_a48556bf8176b82019',NULL,'web','/web/','n. 网, 蛛丝, 蹼, 织物, 圈套, 卷筒纸\nvi. 结网, 形成网\nvt. 织蜘蛛网于, 使落入圈套；英英释义：n. an intricate network suggesting something that was formed by weaving or interweaving\nn. an intricate trap that entangles or ensnares its victim\nn. a fabric (especially a fabric in the process of being woven)\nn. membrane connecting the toes of some aquatic birds and mammals；词形变化：s:webs/i:webbing/p:webbed/3:webs/d:webbed','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ecac33931b92a3056b',NULL,'wedding','/''wediŋ/','n. 婚礼, 结婚, 结婚周年纪念日, 结合\n[法] 结婚, 婚礼, 结婚纪念日；英英释义：n. the social event at which the ceremony of marriage is performed\nn. a party of people at a wedding；词形变化：s:weddings/i:wedding/0:wedding/1:i','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_ec3017dd0249f0914d',NULL,'wedge','/wedʒ/','n. 楔子, 楔形物, 起因, 导致分裂的东西\nvt. 楔住, 挤进, 楔入\nvi. 楔入, 挤进；英英释义：n. any shape that is triangular in cross section\nn. (golf) an iron with considerable loft and a broad sole\nn. something solid that is usable as an inclined plane (shaped like a V) that can be pushed between two things to separate them\nv. squeeze like a wedge into a tight space；词形变化：s:wedges/d:wedged/p:wedged/i:wedging/3:wedges','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_31e5c592572fa8f189',NULL,'weed','/wi:d/','n. 杂草, 野草\nvi. 除草\nvt. 除...的草, 剔除；英英释义：n. any plant that crowds out cultivated plants\nn. a black band worn by a man (on the arm or hat) as a sign of mourning\nv. clear of weeds；词形变化：0:wee/1:dp/s:weeds/i:weeding/d:weeded/p:weeded/3:weeds','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
