INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_03ff8af93285c5626b',NULL,'weld','/weld/','n. 焊接处, 焊接\nvt. 焊接, 使密接, 使结合, 使成整体\nvi. 焊牢；英英释义：n. United States abolitionist (1803-1895)\nn. a metal joint formed by softening with heat and fusing or hammering together\nv. join together by heating\nv. unite closely or intimately；词形变化：d:welded/p:welded/i:welding/s:welds/3:welds','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_2ba95c0925754c99d6',NULL,'welfare','/''welfєә/','n. 福利, 安宁, 幸福, 福利事业\na. 福利的；英英释义：n governmental provision of economic assistance to persons in need\nn something that aids or promotes well-being\nn a contented state of being happy and healthy and prosperous','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
