INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('77c4ba2f-9bda-450a-8335-f50616205037',NULL,'whereas','/hwєәr''æz/','conj. 然而, 鉴于\n[法] 考虑到, 鉴于, 就...而论；英英释义：adv. At which place; where.\nconj. Considering that; it being the case that; since; --\n used to introduce a preamble which is the basis of declarations,\n affirmations, commands, requests, or like, that follow.\nconj. When in fact; while on the contrary; the case being in\n truth that; although; -- implying opposition to something that\n precedes; or implying recognition of facts, sometimes followed by a\n different statement, and sometimes by inferences or something\n consequent.','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('da3d2f71-37c2-4b5e-8221-c326d72e6dbe',NULL,'whereby','/(h)weә''bai/','adv. 靠什么, 如何, 为何, 靠那个, 因此, 由此\n[法] 因此, 由是；英英释义：adv. By which; -- used relatively.\nadv. By what; how; -- used interrogatively.','','考研核心·提高','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
