INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_4c74eef2200190f7cf',NULL,'whip','/hwip/','n. 鞭子, 抽打, 车夫, 搅拌器\nvt. 鞭打, 搅拌, 煽动, 召集, 仓促制成\nvi. 拍击, 急走, 抽打；英英释义：n. an instrument with a handle and a flexible lash that is used for whipping\nn. a legislator appointed by the party to enforce discipline\nn. a dessert made of sugar and stiffly beaten egg whites or cream and usually flavored with fruit\nn. (golf) the flexibility of the shaft of a golf club；词形变化：s:whips/p:whipped/i:whipping/d:whipped/3:whips','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
