INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_1b950fc4b1a650ce0e',NULL,'whisky','/''hwiski/','n. 威士忌酒, 轻便马车\n[化] 威士忌酒；英英释义：n a liquor made from fermented mash of grain；词形变化：s:whiskies','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_708a87c1a958949a32',NULL,'whisper','/''hwispә/','n. 耳语, 密谈, 谣传, 沙沙声\nvi. 耳语, 密谈, 沙沙地响\nvt. 低声说；英英释义：n. speaking softly without vibration of the vocal cords\nv. speak softly; in a low voice；词形变化：p:whispered/i:whispering/s:whispers/3:whispers/d:whispered','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_139ac9d4450eadd662',NULL,'whistle','/''hwisl/','n. 口哨, 汽笛, 啸啸声, 口哨声\nvi. 吹口哨, 鸣汽笛, 发嘘嘘声\nvt. 用口哨或吹哨传意, 用口哨演奏；英英释义：n. the sound made by something moving rapidly or by steam coming out of a small aperture\nn. the act of signalling (e.g., summoning) by whistling or blowing a whistle\nn. a small wind instrument that produces a whistling sound by blowing into it\nn. acoustic device that forces air or steam against an edge or into a cavity and so produces a loud shrill sound；词形变化：p:whistled/i:whistling/s:whistles/3:whistles/d:whistled','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_07c041f3906def53e5',NULL,'whitewash','/''hwaitwɒʃ/','n. 白色涂料, 粉饰, 得零分的惨败；英英释义：n. a defeat in which the losing person or team fails to score\nn. wash consisting of lime and size in water; used for whitening walls and other surfaces\nn. a specious or deceptive clearing that attempts to gloss over failings and defects\nv. cover up a misdemeanor, fault, or error；词形变化：d:whitewashed/p:whitewashed/i:whitewashing/s:whitewashes/3:whitewashes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_070071e58b9a4a1edf',NULL,'whoever','/hu''evә/','pron. 任何人, 无论谁；英英释义：pron. Whatever person; any person who; be or she who; any one\n who; as, he shall be punished, whoever he may be.','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_5ce893fea0f229ce82',NULL,'whole','/hәul/','n. 全部, 全体, 整体, 完全之体系\na. 所有的, 完整的, 完全的, 纯粹的；英英释义：n. all of something including all its component elements or parts\nn. an assemblage of parts that is regarded as a single entity\na. including all components without exception; being one unit or constituting the full amount or extent or duration; complete\na. (of siblings) having the same parents；词形变化：s:wholes','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
