INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_a8f582155bbffae213',NULL,'wisdom','/''wizdәm/','n. 智慧, 明智行为, 学识, 名言, 贤人；英英释义：n. accumulated knowledge or erudition or enlightenment\nn. the trait of utilizing knowledge and experience with common sense and insight\nn. ability to apply knowledge or experience or understanding or common sense and insight\nn. the quality of being prudent and sensible；词形变化：s:wisdoms','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
