INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_850bc4ef1e39ede04d',NULL,'worst','/wә:st/','n. 最坏, 最坏的时候\na. 最坏的, 最恶劣的, 最不利的\nadv. 最坏, 最糟；英英释义：n. the least favorable outcome\nn. the greatest damage or wickedness of which one is capable\nn. the weakest effort or poorest achievement one is capable of\nv. defeat thoroughly；词形变化：0:bad/1:t/d:worsted/3:worsts/r:worst/i:/p:','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
