INSERT INTO vocabulary (id,user_id,word,phonetic,meaning,example,category,subject,mastery,review_count,is_custom,last_reviewed,next_review) VALUES ('vocab_ky_0d70bf06f1b4bc3c9d',NULL,'yard','/jɑ:d/','n. 码, 庭院, 工场\n[化] 堆置场；英英释义：n. a unit of length equal to 3 feet; defined as 91.44 centimeters; originally taken to be the average length of a stride\nn. the enclosed land around a house or other building\nn. a tract of land enclosed for particular activities (sometimes paved and usually associated with buildings)\nn. a tract of land where logs are accumulated；词形变化：s:yards','','考研核心·基础','english','0','0','0',NULL,NULL) ON CONFLICT(id) DO UPDATE SET word=excluded.word,phonetic=excluded.phonetic,meaning=excluded.meaning,category=excluded.category;
